// Install: dotnet add package Microsoft.Extensions.Caching.Hybrid

builder.Services.AddHybridCache(opt =>
{
    opt.DefaultEntryOptions = new HybridCacheEntryOptions
    {
        Expiration = TimeSpan.FromMinutes(5),          // L2 TTL
        LocalCacheExpiration = TimeSpan.FromMinutes(1) // L1 TTL (ngắn hơn)
    };
    opt.MaximumPayloadBytes = 1024 * 1024; // 1MB max
});

// L2 via Redis (optional)
builder.Services.AddStackExchangeRedisCache(opt =>
    opt.Configuration = config["Redis"]);

// Usage
public class ProductService(HybridCache cache, ProductRepo repo)
{
    public async Task<ProductDto?> GetAsync(int id, CancellationToken ct)
    {
        return await cache.GetOrCreateAsync(
            $"product:{id}",
            async innerCt => await repo.GetDtoAsync(id, innerCt),
            options: new HybridCacheEntryOptions { Expiration = TimeSpan.FromMinutes(10) },
            cancellationToken: ct);
    }

    public async Task InvalidateAsync(int id, CancellationToken ct) =>
        await cache.RemoveAsync($"product:{id}", ct);
}
